def pong(r, s, d):
    a = [[0 for _ in range(s)] for _ in range(r)]
    i = j = 0
    di, dj = 1 if r > 1 else 0, 1 if s > 1 else 0

    for b in range(1, d + 1):
        a[i][j] = b

        if di == 0:
            pass
        elif di == 1:
            if 0 < i == r - 1:
                di = -1
        else:
            if i == 0:
                di = 1

        if dj == 0:
            pass
        elif dj == 1:
            if j == s - 1:
                dj = -1
        else:
            if j == 0:
                dj = 1

        i += di
        j += dj


    return a
